type ExecuteLoopWorkerSpec struct {
	// ProjectRoot overrides the manager's default project root for this worker.
	// When set, the worker scans and executes beads from this project instead of
	// the server's primary working directory. Must be an absolute path to a
	// directory containing a .ddx/ folder. Validated by the server before the
	// worker starts.
	ProjectRoot  string        `json:"project_root,omitempty"`
	Harness      string        `json:"harness,omitempty"`
	Model        string        `json:"model,omitempty"`
	Profile      string        `json:"profile,omitempty"`
	Provider     string        `json:"provider,omitempty"`
	ModelRef     string        `json:"model_ref,omitempty"`
	Effort       string        `json:"effort,omitempty"`
	LabelFilter  string        `json:"label_filter,omitempty"`
	Once         bool          `json:"once,omitempty"`
	PollInterval time.Duration `json:"poll_interval,omitempty"`
	// Review options — controls the post-merge review agent.
	NoReview      bool   `json:"no_review,omitempty"`
	ReviewHarness string `json:"review_harness,omitempty"`
	ReviewModel   string `json:"review_model,omitempty"`
	// OpaquePassthrough, when true, skips DDx-side route validation and config
	// harness/model injection. Routing belongs to the agent service (CONTRACT-003
	// / FEAT-010 / ddx-c4231775). Set by ddx work; not set by ddx agent execute-loop.
	OpaquePassthrough bool `json:"opaque_passthrough,omitempty"`
}

type PluginActionWorkerSpec struct {
	ProjectRoot string `json:"project_root,omitempty"`
	Name        string `json:"name"`
	Action      string `json:"action"`
	Scope       string `json:"scope"`
}

type PluginActionExecutor func(ctx context.Context) (string, error)

// Terminal phases per FEAT-006.
var terminalPhases = map[string]bool{
	"done":      true,
	"preserved": true,
	"failed":    true,
}

// CurrentAttemptInfo is the in-flight attempt summary embedded in WorkerRecord.
type CurrentAttemptInfo struct {
	AttemptID string    `json:"attempt_id"`
	BeadID    string    `json:"bead_id"`
	BeadTitle string    `json:"bead_title,omitempty"`
	Harness   string    `json:"harness,omitempty"`
	Model     string    `json:"model,omitempty"`
	Profile   string    `json:"profile,omitempty"`
	Phase     string    `json:"phase"`
	PhaseSeq  int       `json:"phase_seq"`
	StartedAt time.Time `json:"started_at"`
	ElapsedMS int64     `json:"elapsed_ms"`
}

// PhaseTransition is one phase-transition entry in WorkerRecord.RecentPhases.
// Only phase-transition events (heartbeat=false) are stored here; heartbeats
// are not retained.
type PhaseTransition struct {
	Phase    string    `json:"phase"`
	TS       time.Time `json:"ts"`
	PhaseSeq int       `json:"phase_seq"`
}

// LastAttemptInfo summarises the most recently completed attempt.
type LastAttemptInfo struct {
	AttemptID string    `json:"attempt_id"`
	BeadID    string    `json:"bead_id"`
	Phase     string    `json:"phase"`
	StartedAt time.Time `json:"started_at"`
	EndedAt   time.Time `json:"ended_at"`
	ElapsedMS int64     `json:"elapsed_ms"`
}

type WorkerLifecycleEvent struct {
	Action    string    `json:"action"`
	Actor     string    `json:"actor"`
	Timestamp time.Time `json:"timestamp"`
	Detail    string    `json:"detail,omitempty"`
	BeadID    string    `json:"bead_id,omitempty"`
}

type WorkerRecord struct {
	ID    string `json:"id"`
	Kind  string `json:"kind"`
	State string `json:"state"`
	// Substate is a non-terminal annotation on a running worker. Currently
	// the only value is "idle" — set when the long-running drain loop has
	// no ready work and is sleeping between polls (ddx-dc157075 AC #5).
	// Cleared as soon as the loop picks up a candidate. Always empty for
	// terminal states (exited/failed/stopped/reaped).
	Substate       string                 `json:"substate,omitempty"`
	Status         string                 `json:"status,omitempty"`
	ProjectRoot    string                 `json:"project_root"`
	Harness        string                 `json:"harness,omitempty"`
	Provider       string                 `json:"provider,omitempty"`
	Model          string                 `json:"model,omitempty"`
	Profile        string                 `json:"profile,omitempty"`
	Effort         string                 `json:"effort,omitempty"`
	Once           bool                   `json:"once,omitempty"`
	PollInterval   string                 `json:"poll_interval,omitempty"`
	StartedAt      time.Time              `json:"started_at,omitempty"`
	FinishedAt     time.Time              `json:"finished_at,omitempty"`
	Error          string                 `json:"error,omitempty"`
	StdoutPath     string                 `json:"stdout_path,omitempty"`
	SpecPath       string                 `json:"spec_path,omitempty"`
	Attempts       int                    `json:"attempts,omitempty"`
	Successes      int                    `json:"successes,omitempty"`
	Failures       int                    `json:"failures,omitempty"`
	CurrentBead    string                 `json:"current_bead,omitempty"`
	LastError      string                 `json:"last_error,omitempty"`
	LastResult     *WorkerExecutionResult `json:"last_result,omitempty"`
	CurrentAttempt *CurrentAttemptInfo    `json:"current_attempt,omitempty"`
	RecentPhases   []PhaseTransition      `json:"recent_phases,omitempty"`
	LastAttempt    *LastAttemptInfo       `json:"last_attempt,omitempty"`
	Lifecycle      []WorkerLifecycleEvent `json:"lifecycle,omitempty"`
	LandSummary    *CoordinatorMetrics    `json:"land_summary,omitempty"`
	// PID is the OS process id of an external worker subprocess, if any.
	// Zero for purely in-process (goroutine-only) workers. Surfaced so the
	// autonomous watchdog can send SIGTERM/SIGKILL to the process group when
	// cancelling the context is not enough.
	PID int `json:"pid,omitempty"`
	// ReapReason is populated when the watchdog forcibly terminates a worker;
	// set to "watchdog" today.
	ReapReason string `json:"reap_reason,omitempty"`
	// PIDAlive is a computed field populated by List(); it is never persisted
	// to disk. True when PID > 0 and the process is alive, false when PID > 0
	// but the process has exited. Omitted (nil) when PID == 0 (goroutine-only).
	PIDAlive *bool `json:"pid_alive,omitempty"`
}

type WorkerExecutionResult struct {
	BeadID     string `json:"bead_id,omitempty"`
	AttemptID  string `json:"attempt_id,omitempty"`
	WorkerID   string `json:"worker_id,omitempty"`
	Harness    string `json:"harness,omitempty"`
	Tier       string `json:"tier,omitempty"`
	Provider   string `json:"provider,omitempty"`
	Model      string `json:"model,omitempty"`
	Status     string `json:"status,omitempty"`
	Detail     string `json:"detail,omitempty"`
	SessionID  string `json:"session_id,omitempty"`
	BaseRev    string `json:"base_rev,omitempty"`
	ResultRev  string `json:"result_rev,omitempty"`
	RetryAfter string `json:"retry_after,omitempty"`
}

type workerHandle struct {
	record  WorkerRecord
	cancel  context.CancelFunc
	logBuf  *bytes.Buffer
	logFile *os.File
	// progressCh receives ProgressEvents from the execute-bead loop.
	// The WorkerManager drains this channel to update WorkerRecord and
	// broadcast to SSE subscribers.
	progressCh chan agent.ProgressEvent
	// progressSubs holds active SSE subscriber channels for this worker.
	progressSubs []chan agent.ProgressEvent
	// progressDone is closed when drainProgress exits, signalling that
	// no further events will arrive and all new subscriptions should
	// receive an immediately-closed channel.
	progressDone chan struct{}
	// lastPhaseTS is the wall-clock time of the most recent non-heartbeat
	// ProgressEvent. The watchdog uses this to detect stalled attempts.
	lastPhaseTS time.Time
	// reaped is set true once the watchdog has escalated this worker. It is
	// checked under m.mu to make reaping idempotent.
	reaped bool
	// stopped is set true once an operator-driven Stop has started the
	// graceful termination path. Checked under m.mu so a second Stop is a
	// no-op and runWorker can preserve the "stopped" state across its final
	// record write.
	stopped bool
	// wakeCh, when non-nil, signals an execute-loop worker's idle-poll
	// sleep to return early so the loop re-scans the ready queue. The
	// channel is buffered (cap 1) so a non-blocking send coalesces multiple
	// wake calls into at most one extra tick. Set on execute-loop workers;
	// nil on plugin-action workers.
	wakeCh chan struct{}
}

// WorkerManager manages in-process execute-loop workers as goroutines.
type WorkerManager struct {
	projectRoot string
	rootDir     string
	// BeadWorkerFactory, when non-nil, is called by runWorker to create the
	// ExecuteBeadWorker instead of building one from the real agent runner.
	// Override in tests to inject a fake executor.
	BeadWorkerFactory func(store agent.ExecuteBeadLoopStore) *agent.ExecuteBeadWorker

	// LandCoordinators is the per-project registry of land coordinators.
	// Exported so tests and server integration tests can stop coordinators
	// on teardown, or inject a custom LandingGitOps via
	// LandCoordinators.gitOpsOverride.
	LandCoordinators *coordinatorRegistry

	// Watchdog parameters. Zero values fall back to defaults:
	//   WatchdogDeadline      = 6h  (total worker runtime budget)
	//   StallDeadline         = 1h  (max phase-transition gap before reap)
	//   WatchdogCheckInterval = 1m  (how often the supervisor sweeps)
	//   WatchdogKillGrace     = 30s (SIGTERM → SIGKILL grace window)
	// Tests override these to run the watchdog on millisecond scales.
	WatchdogDeadline      time.Duration
	StallDeadline         time.Duration
	WatchdogCheckInterval time.Duration
	WatchdogKillGrace     time.Duration

	mu      sync.Mutex
	workers map[string]*workerHandle

	watchdogOnce sync.Once
	watchdogStop chan struct{}
}

const (
	defaultWatchdogDeadline      = 6 * time.Hour
	defaultStallDeadline         = 1 * time.Hour
	defaultWatchdogCheckInterval = 1 * time.Minute
	defaultWatchdogKillGrace     = 30 * time.Second
)

// WakeProject signals every running execute-loop worker bound to projectRoot
// to skip its current idle-poll sleep and re-scan the ready queue. Used by
// the operator-prompt approve / auto-approve mutations (Story 15) so a
// freshly-approved bead is claimed immediately rather than after a full
// PollInterval. The send is non-blocking and the per-worker wake channel is
// buffered (cap 1), so multiple wakes within one tick coalesce. Returns the
// number of workers signalled (0 when no execute-loop is running for the
// project — submit/approve still succeeds, the next tick on a future worker
// will pick the bead up).
func (m *WorkerManager) WakeProject(projectRoot string) int {
	m.mu.Lock()
	defer m.mu.Unlock()
	signalled := 0
	for _, h := range m.workers {
		if h == nil || h.wakeCh == nil {
			continue
		}
		if h.record.ProjectRoot != projectRoot {
			continue
		}
		select {
		case h.wakeCh <- struct{}{}:
			signalled++
		default:
			// Wake already pending — coalesce.
			signalled++
		}
	}
	return signalled
}

func NewWorkerManager(projectRoot string) *WorkerManager {
	m := &WorkerManager{
		projectRoot:      projectRoot,
		rootDir:          filepath.Join(projectRoot, ".ddx", "workers"),
		workers:          map[string]*workerHandle{},
		LandCoordinators: newCoordinatorRegistry(),
		watchdogStop:     make(chan struct{}),
	}
	m.applyServerWatchdogConfig(projectRoot)
	return m
}

func lifecycleStartDetail(spec ExecuteLoopWorkerSpec) string {
	parts := []string{"kind=execute-loop"}
	if spec.Harness != "" {
		parts = append(parts, "harness="+spec.Harness)
	}
	if spec.Profile != "" {
		parts = append(parts, "profile="+agent.NormalizeRoutingProfile(spec.Profile))
	}
	if spec.Effort != "" {
		parts = append(parts, "effort="+spec.Effort)
	}
	if spec.LabelFilter != "" {
		parts = append(parts, "label_filter="+spec.LabelFilter)
	}
	return strings.Join(parts, " ")
}

// applyServerWatchdogConfig reads .ddx/config.yaml at projectRoot and applies
// any server.watchdog_deadline / server.stall_deadline overrides. Invalid or
// missing values are silently ignored — defaults are filled in by the
// watchdog loop at runtime.
func (m *WorkerManager) applyServerWatchdogConfig(projectRoot string) {
	cfg, err := config.LoadWithWorkingDir(projectRoot)
	if err != nil || cfg == nil || cfg.Server == nil {
		return
	}
	if d, err := time.ParseDuration(cfg.Server.WatchdogDeadline); err == nil && d > 0 {
		m.WatchdogDeadline = d
	}
	if d, err := time.ParseDuration(cfg.Server.StallDeadline); err == nil && d > 0 {
		m.StallDeadline = d
	}
}

// watchdogDeadlines returns the effective deadlines, applying defaults for
// any zero-valued fields.
func (m *WorkerManager) watchdogDeadlines() (watchdog, stall, check, grace time.Duration) {
	watchdog = m.WatchdogDeadline
	if watchdog <= 0 {
		watchdog = defaultWatchdogDeadline
	}
	stall = m.StallDeadline
	if stall <= 0 {
		stall = defaultStallDeadline
	}
	check = m.WatchdogCheckInterval
	if check <= 0 {
		check = defaultWatchdogCheckInterval
	}
	grace = m.WatchdogKillGrace
	if grace <= 0 {
		grace = defaultWatchdogKillGrace
	}
	return
}

func (m *WorkerManager) StartExecuteLoop(spec ExecuteLoopWorkerSpec) (WorkerRecord, error) {
	// Resolve the effective project root: spec override takes priority over the
	// manager's default so callers can target any registered project.
	effectiveRoot := spec.ProjectRoot
	if effectiveRoot == "" {
		effectiveRoot = m.projectRoot
	}

	// Pre-flight: validate harness availability and model compatibility
	// before creating the worker record or claiming any beads.
	// Skipped when OpaquePassthrough=true (ddx work path): routing belongs to
	// the agent service; DDx must not pre-resolve or validate the route.
	if !spec.OpaquePassthrough {
		if err := agent.ValidateForExecuteLoopViaService(context.Background(), effectiveRoot, spec.Harness, spec.Model, spec.Provider, spec.ModelRef); err != nil {
			return WorkerRecord{}, fmt.Errorf("execute-loop: %w", err)
		}
	}

	if err := os.MkdirAll(m.rootDir, 0o755); err != nil {
		return WorkerRecord{}, err
	}

	id := "worker-" + time.Now().UTC().Format("20060102T150405") + "-" + randomSuffix(4)
	dir := filepath.Join(m.rootDir, id)
	if err := os.MkdirAll(dir, 0o755); err != nil {
		return WorkerRecord{}, err
	}

	// Write spec
	specData, _ := json.MarshalIndent(spec, "", "  ")
	_ = os.WriteFile(filepath.Join(dir, "spec.json"), append(specData, '\n'), 0o644)

	// Open log file
	logPath := filepath.Join(dir, "worker.log")
	logFile, err := os.OpenFile(logPath, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, 0o644)
	if err != nil {
		return WorkerRecord{}, err
	}

	// Open structured event sink — loop milestones (bead.claimed, bead.result,
	// loop.start/end) land here as JSONL so log aggregators and future server
	// endpoints can parse them independently of the human-readable worker.log.
	eventsPath := filepath.Join(dir, "worker-events.jsonl")
	eventsFile, eventsErr := os.OpenFile(eventsPath, os.O_CREATE|os.O_WRONLY|os.O_TRUNC, 0o644)
	if eventsErr != nil {
		eventsFile = nil // non-fatal; structured events silently disabled
	}

	record := WorkerRecord{
		ID:           id,
		Kind:         "execute-loop",
		State:        "running",
		Status:       "running",
		ProjectRoot:  effectiveRoot,
		Harness:      spec.Harness,
		Model:        spec.Model,
		Profile:      agent.NormalizeRoutingProfile(spec.Profile),
		Effort:       spec.Effort,
		Once:         spec.Once,
		PollInterval: spec.PollInterval.String(),
		StdoutPath:   relToProject(m.projectRoot, logPath),
		SpecPath:     relToProject(m.projectRoot, filepath.Join(dir, "spec.json")),
		StartedAt:    time.Now().UTC(),
	}
	record.Lifecycle = append(record.Lifecycle, WorkerLifecycleEvent{
		Action:    "start",
		Actor:     "local-operator",
		Timestamp: record.StartedAt,
		Detail:    lifecycleStartDetail(spec),
	})
	_ = m.writeRecord(dir, record)

	ctx, cancel := context.WithCancel(context.Background())

package agent

import (
	"context"
	"encoding/json"
	"fmt"
	"os"
	"time"

	agentlib "github.com/DocumentDrivenDX/fizeau"
)

// Public event-type strings emitted by agentlib.FizeauService.Execute, mirrored
// from CONTRACT-003 §"Event JSON shapes". Kept as constants here so the
// drain loop does not have to import the agent's internal/harnesses
// package (which is module-private).
const (
	serviceEventRoutingDecision = "routing_decision"
	serviceEventFinal           = "final"
)

// ServiceEvent payload types are now aliases to the upstream v0.8.0 public
// types (agent-f0bc5467). DDx previously maintained byte-for-byte shadow
// copies of these structs because CONTRACT-003 hadn't published them; that
// left the consumer carrying stream-adjacent knowledge and drifted whenever
// upstream shapes changed. With v0.8.0 the types are public and stable.
//
// Aliases rather than an outright delete so existing call sites keep
// working without a sweep. New code can (and should) use agentlib types
// directly.
type (
	serviceFinalData = agentlib.ServiceFinalData
)

type serviceRoutingActual struct {
	Harness                     string
	Provider                    string
	Model                       string
	PredictedPower              int
	PredictedSpeedTPS           float64
	PredictedCostUSDPer1kTokens float64
	PredictedCostSource         string
}

// useNewAgentPath reports whether RunAgent should dispatch to the new
// agentlib.FizeauService.Execute path. Default is on. Set the env var
// DDX_USE_NEW_AGENT_PATH=0 (or "false") to disable as an emergency escape
// hatch.
func useNewAgentPath() bool {
	switch os.Getenv("DDX_USE_NEW_AGENT_PATH") {
	case "0", "false", "FALSE", "False":
		return false
	default:
		return true
	}
}

// runAgentViaService is the new RunAgent dispatch path that drives the
// agent through agentlib.FizeauService.Execute and drains the resulting event
// channel into a DDx Result. Old in-package code paths (RunAgent legacy
// loop, embeddedCompactionConfig, buildAgentProvider, findTool, and
// wrapProviderWithDeadlines) stay in place; this function does NOT call them.
//
// Stall detection: we delegate to the agent's StallPolicy. The agent
// emits a stall event then a final event with Status="stalled".
func runAgentViaService(r *Runner, opts RunArgs) (*Result, error) {
	promptText, err := r.resolvePrompt(opts)
	if err != nil {
		return nil, err
	}

	model := r.resolveModel(opts, "agent")
	timeout := r.resolveTimeout(opts)
	wallClock := r.resolveWallClock(opts)

	wd := opts.WorkDir
	if wd == "" {
		wd, _ = os.Getwd()
	}

	// Construct the service. Reuses NewServiceFromWorkDir so provider/model
	// routing data lands on the agent the same way every other DDx command
	// constructs it (see serviceconfig.go).
	svc, err := NewServiceFromWorkDir(wd)
	if err != nil {
		return nil, fmt.Errorf("agent: build service: %w", err)
	}

	// Resolve where to write the per-request session log.
	logDir := opts.SessionLogDir
	if logDir == "" {
		logDir = r.Config.SessionLogDir
	}
	if logDir == "" {
		logDir = DefaultLogDir
	}

	providerTimeout := ResolveProviderRequestTimeout(wd, opts.Provider, model, 0)

	// Build the public ExecuteRequest per CONTRACT-003.
	req := agentlib.ServiceExecuteRequest{
		Prompt:          promptText,
		Model:           model,
		Provider:        opts.Provider,
		Harness:         "agent",
		ModelRef:        opts.ModelRef,
		Reasoning:       agentlib.Reasoning(opts.Effort),
		Permissions:     opts.Permissions,
		WorkDir:         wd,
		Timeout:         wallClock,
		IdleTimeout:     timeout,
		ProviderTimeout: providerTimeout,
		SessionLogDir:   logDir,
		Metadata:        opts.Correlation,
		Role:            opts.Role,
		CorrelationID:   opts.CorrelationID,
	}

	parentCtx := opts.Context
	if parentCtx == nil {
		parentCtx = context.Background()
	}
	ctx, cancel := context.WithCancel(parentCtx)
	defer cancel()

	start := time.Now()
	events, err := svc.Execute(ctx, req)
	if err != nil {
		return nil, fmt.Errorf("agent: execute: %w", err)
	}

	final, routing, actualPower, _ := drainServiceEvents(events)
	elapsed := time.Since(start)

	result := &Result{
		Harness:    "agent",
		Model:      model,
		DurationMS: int(elapsed.Milliseconds()),
	}
	if routing != nil {
		result.Provider = routing.Provider
		if routing.Model != "" {
			result.Model = routing.Model
		}
		result.PredictedPower = routing.PredictedPower
		result.PredictedSpeedTPS = routing.PredictedSpeedTPS
		result.PredictedCostUSDPer1kTokens = routing.PredictedCostUSDPer1kTokens
		result.PredictedCostSource = routing.PredictedCostSource
	}
	if actualPower > 0 {
		result.ActualPower = actualPower
	}
	if final != nil {
		// Normalized final text from the upstream harness (agent-32e8ff5e).
		result.Output = final.FinalText
		if final.Usage != nil {
			// v0.9.1: Usage fields became *int so the API can distinguish
			// "harness reported zero" from "harness didn't report". Treat
			// nil as zero for DDx's int-valued result struct.
			if final.Usage.InputTokens != nil {
				result.InputTokens = *final.Usage.InputTokens
			}
			if final.Usage.OutputTokens != nil {
				result.OutputTokens = *final.Usage.OutputTokens
			}
			if final.Usage.TotalTokens != nil {
				result.Tokens = *final.Usage.TotalTokens
			}
		}
		if final.CostUSD > 0 {
			result.CostUSD = final.CostUSD
		}
		result.ExitCode = final.ExitCode
		result.Error = final.Error
		if final.RoutingActual != nil {
			if result.Provider == "" {
				result.Provider = final.RoutingActual.Provider
			}
			if final.RoutingActual.Model != "" {
				result.Model = final.RoutingActual.Model
			}
		}
		if final.SessionLogPath != "" {
			// surface as session ID for downstream cross-reference (mirrors
			// the legacy path's AgentSessionID population).
			result.AgentSessionID = final.SessionLogPath
		}
	}
	result.Error = appendProviderTimeoutHint(result.Error, providerTimeout)

	promptSource := opts.PromptSource
	if promptSource == "" {
		if opts.PromptFile != "" {
			promptSource = opts.PromptFile
		} else {
			promptSource = "inline"
		}
	}
	r.logSession(result, len(promptText), promptText, promptSource, opts.Correlation)
	r.recordRoutingOutcome(result, elapsed, opts)
	return result, nil
}

// drainServiceEvents reads service events and returns the final-event payload,
// the routing decision (when present in the routing_decision start event), the
// power of the selected model (0 when the routing_decision event does not
// include candidate power components), and any canonical progress payloads
// emitted by the service.
func drainServiceEvents(events <-chan agentlib.ServiceEvent) (*serviceFinalData, *serviceRoutingActual, int, []agentlib.ServiceProgressData) {
	var final *serviceFinalData
	var routing *serviceRoutingActual
	var routingPower int
	var progress []agentlib.ServiceProgressData

	for ev := range events {
		switch string(ev.Type) {
		case serviceEventRoutingDecision:
			var payload struct {
				Harness    string `json:"harness"`
				Provider   string `json:"provider"`
				Model      string `json:"model"`
				Candidates []struct {
					Model              string  `json:"model"`
					Eligible           bool    `json:"eligible"`
					CostUSDPer1kTokens float64 `json:"cost_usd_per_1k_tokens"`
					CostSource         string  `json:"cost_source"`
					Components         struct {
						Power    int     `json:"power"`
						SpeedTPS float64 `json:"speed_tps"`
					} `json:"components"`
				} `json:"candidates"`
			}
			if err := json.Unmarshal(ev.Data, &payload); err == nil {
				routing = &serviceRoutingActual{
					Harness:  payload.Harness,
					Provider: payload.Provider,
					Model:    payload.Model,
				}
				for _, c := range payload.Candidates {
					if c.Eligible && c.Model == payload.Model {
						routingPower = c.Components.Power
						routing.PredictedPower = c.Components.Power
						routing.PredictedSpeedTPS = c.Components.SpeedTPS
						routing.PredictedCostUSDPer1kTokens = c.CostUSDPer1kTokens
						routing.PredictedCostSource = c.CostSource
						break
					}
				}
			}
		case agentlib.ServiceEventTypeProgress:
			var data agentlib.ServiceProgressData
			if err := json.Unmarshal(ev.Data, &data); err == nil {
				progress = append(progress, data)
			}
		case serviceEventFinal:
			var data serviceFinalData
			if err := json.Unmarshal(ev.Data, &data); err == nil {
				final = &data
			}
		}
	}
	return final, routing, routingPower, progress
}

package agent

import (
	"bufio"
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"os"
	osexec "os/exec"
	"path/filepath"
	"strings"
	"sync"
	"time"
)

// claudeStreamEvent is a minimal, lenient view of a claude CLI stream-json
// event. Only the fields we need for progress and final result are decoded.
type claudeStreamEvent struct {
	Type    string          `json:"type"`
	Subtype string          `json:"subtype"`
	Message json.RawMessage `json:"message"`
	Result  string          `json:"result"`

	// result-event fields
	Usage struct {
		InputTokens         int `json:"input_tokens"`
		OutputTokens        int `json:"output_tokens"`
		CacheCreationTokens int `json:"cache_creation_input_tokens"`
		CacheReadTokens     int `json:"cache_read_input_tokens"`
	} `json:"usage"`
	TotalCostUSD    float64 `json:"total_cost_usd"`
	DurationMsField int64   `json:"duration_ms"`
	SessionID       string  `json:"session_id"`
	IsError         bool    `json:"is_error"`

	// system/init fields
	Model string `json:"model"`
}

// claudeAssistantMessage is the shape of the "message" field in an
// {"type":"assistant",...} stream-json event. It is Claude's native
// Messages API payload.
type claudeAssistantMessage struct {
	ID      string               `json:"id"`
	Model   string               `json:"model"`
	Content []claudeMessageBlock `json:"content"`
	Usage   claudeAssistantUsage `json:"usage"`
	Stop    string               `json:"stop_reason,omitempty"`
}

type claudeMessageBlock struct {
	Type     string          `json:"type"`
	Text     string          `json:"text,omitempty"`
	Thinking string          `json:"thinking,omitempty"`
	ID       string          `json:"id,omitempty"`
	Name     string          `json:"name,omitempty"`
	Input    json.RawMessage `json:"input,omitempty"`
}

type claudeAssistantUsage struct {
	InputTokens              int `json:"input_tokens"`
	OutputTokens             int `json:"output_tokens"`
	CacheCreationInputTokens int `json:"cache_creation_input_tokens"`
	CacheReadInputTokens     int `json:"cache_read_input_tokens"`
}

// claudeUserMessage decodes the "message" field of a {"type":"user",...}
// stream event so we can recover tool_result output, error flags, and
// match them back to the originating tool_use_id.
type claudeUserMessage struct {
	Content []claudeUserBlock `json:"content"`
}

type claudeUserBlock struct {
	Type      string          `json:"type"`
	ToolUseID string          `json:"tool_use_id,omitempty"`
	Content   json.RawMessage `json:"content,omitempty"`
	IsError   bool            `json:"is_error,omitempty"`
}

// pendingToolCall tracks an in-flight tool_use awaiting its tool_result.
type pendingToolCall struct {
	name      string
	input     map[string]any
	startedAt time.Time
	turn      int
	elapsedMS int64
}

// claudeStreamResult is the aggregated final state from parsing a
// claude stream-json output.
type claudeStreamResult struct {
	FinalText    string
	SessionID    string
	Model        string
	InputTokens  int
	OutputTokens int
	CostUSD      float64
	ToolCalls    int
	TurnCount    int
	IsError      bool
}

// parseClaudeStream reads newline-delimited claude stream-json events from r,
// writes translated progress entries to progressLog, and returns an aggregated
// claudeStreamResult covering token usage, final text, and counts.
//
// The progress entries use the same event type names the Fizeau harness
// emits (session.start, llm.response, tool.call, tool.result) so the existing
// TailSessionLogs / FormatSessionLogLines pipeline can render them as
// real-time progress without any changes.
//
// beadID and startTime are optional: when provided, each progress entry
// receives a data.bead_id and data.elapsed_ms field for cross-referencing.
//
// progressLog may be nil; if nil, progress entries are discarded but the
// aggregate result is still returned.
func parseClaudeStream(r io.Reader, progressLog io.Writer, sessionID, beadID string, startTime time.Time) (*claudeStreamResult, error) {
	if startTime.IsZero() {
		startTime = time.Now()
	}
	verbose := os.Getenv("DDX_LOG_VERBOSE") == "1"
	pendingTools := map[string]*pendingToolCall{}
	res := &claudeStreamResult{SessionID: sessionID}
	scanner := bufio.NewScanner(r)
	scanner.Buffer(make([]byte, 0, 256*1024), 16*1024*1024) // 16MB max line — claude can dump big tool results

	seq := 0
	emit := func(evType, dataJSON string) {
		if progressLog == nil {
			return
		}
		entry := map[string]any{
			"session_id": sessionID,
			"seq":        seq,
			"type":       evType,
			"ts":         time.Now().UTC().Format(time.RFC3339Nano),
			"data":       json.RawMessage(dataJSON),
		}
		seq++
		line, err := json.Marshal(entry)
		if err != nil {
			return
		}
		_, _ = progressLog.Write(line)
		_, _ = progressLog.Write([]byte("\n"))
	}

	wroteStart := false
	// lastRequestSentAt tracks when the most recent LLM request was sent.
	// For the first turn it equals startTime (the session began with a
	// request). After every "user" event (tool_result returned to the model)
	// we reset it: the next assistant event represents a new round-trip.
	// Per-call latency is then `now - lastRequestSentAt`, distinct from
	// cumulative elapsed_ms.
	lastRequestSentAt := startTime
	for scanner.Scan() {
		line := strings.TrimSpace(scanner.Text())
		if line == "" {
			continue
		}
		var ev claudeStreamEvent
		if err := json.Unmarshal([]byte(line), &ev); err != nil {
			// Not a JSON event — skip silently to be lenient.
			continue
		}

		now := time.Now()
		elapsedMS := now.Sub(startTime).Milliseconds()
		switch ev.Type {
		case "system":
			if ev.Subtype == "init" && !wroteStart {
				wroteStart = true
				if ev.Model != "" {
					res.Model = ev.Model
				}
				if ev.SessionID != "" {
					res.SessionID = ev.SessionID
				}
				data, _ := json.Marshal(map[string]any{
					"model":      res.Model,
					"session_id": res.SessionID,
					"bead_id":    beadID,
					"elapsed_ms": elapsedMS,
					"harness":    "claude",
				})
				emit("session.start", string(data))
			}

		case "assistant":
			var msg claudeAssistantMessage
			if len(ev.Message) > 0 {
				_ = json.Unmarshal(ev.Message, &msg)
			}
			if msg.Model != "" && res.Model == "" {
				res.Model = msg.Model
			}
			// Running usage totals so TailSessionLogs has the latest view.
			if msg.Usage.InputTokens > 0 {
				res.InputTokens = msg.Usage.InputTokens
			}
			if msg.Usage.OutputTokens > 0 {
				res.OutputTokens = msg.Usage.OutputTokens
			}

			// Count each assistant message as one turn for operator visibility.
			res.TurnCount++

			// Collect tool-use names emitted in this turn, so we can translate
			// the assistant event into an llm.response-like progress entry.
			var toolNames []map[string]string
			var textOut strings.Builder
			var responseBytes, thinkingBytes, toolInputBytes int
			for _, block := range msg.Content {
				switch block.Type {
				case "text":
					if block.Text != "" {
						if textOut.Len() > 0 {
							textOut.WriteString("\n")
						}
						textOut.WriteString(block.Text)
						responseBytes += len([]byte(block.Text))
					}
				case "thinking":
					if block.Thinking != "" {
						thinkingBytes += len([]byte(block.Thinking))
					}
				case "tool_use":
					name := block.Name
					if name == "" {
						name = "tool"
					}
					toolNames = append(toolNames, map[string]string{"name": name})
					toolInputBytes += len(block.Input)
				}
			}

			latencyMS := now.Sub(lastRequestSentAt).Milliseconds()
			if latencyMS < 0 {
				latencyMS = 0
			}
			llmData := map[string]any{
				"model":            res.Model,
				"latency_ms":       latencyMS,
				"tool_calls":       toolNames,
				"turn":             res.TurnCount,
				"bead_id":          beadID,
				"elapsed_ms":       elapsedMS,
				"input_tokens":     res.InputTokens,
				"output_tokens":    res.OutputTokens,
				"response_bytes":   responseBytes,
				"thinking_bytes":   thinkingBytes,
				"tool_input_bytes": toolInputBytes,
				"attempt": map[string]any{
					"cost": map[string]any{
						"raw": map[string]any{
							"total_tokens": res.InputTokens + res.OutputTokens,
						},
					},
				},
			}
			if verbose {
				llmData["content"] = textOut.String()
				llmData["finish_reason"] = msg.Stop
				llmData["usage"] = map[string]any{
					"input_tokens":                msg.Usage.InputTokens,
					"output_tokens":               msg.Usage.OutputTokens,
					"cache_creation_input_tokens": msg.Usage.CacheCreationInputTokens,
					"cache_read_input_tokens":     msg.Usage.CacheReadInputTokens,
					"total_tokens":                msg.Usage.InputTokens + msg.Usage.OutputTokens,
				}
			}
			data, _ := json.Marshal(llmData)
			emit("llm.response", string(data))

			// Emit tool.call immediately for every tool_use block. The
			// matching user/tool_result event emits tool.result later.
			for _, block := range msg.Content {
				if block.Type != "tool_use" {
					continue
				}
				res.ToolCalls++
				input := map[string]any{}
				if len(block.Input) > 0 {
					_ = json.Unmarshal(block.Input, &input)
				}
				pendingTools[block.ID] = &pendingToolCall{
					name:      block.Name,
					input:     input,
					startedAt: now,
					turn:      res.TurnCount,
					elapsedMS: elapsedMS,
				}
				toolData, _ := json.Marshal(map[string]any{
					"tool":        block.Name,
					"input":       input,
					"input_bytes": len(block.Input),
					"bead_id":     beadID,
					"elapsed_ms":  elapsedMS,
					"turn":        res.TurnCount,
				})
				emit("tool.call", string(toolData))
			}

			// Save the most recent text content so, if the final result
			// event is missing or truncated, we can still return the
			// agent's last spoken text.
			if t := textOut.String(); t != "" {
				res.FinalText = t
			}

		case "user":
			// user events carry tool_result content. They mark the moment
			// the next LLM request is sent, so we reset the per-call
			// latency baseline.
			if len(ev.Message) > 0 && len(pendingTools) > 0 {
				var um claudeUserMessage
				if json.Unmarshal(ev.Message, &um) == nil {
					for _, blk := range um.Content {
						if blk.Type != "tool_result" || blk.ToolUseID == "" {
							continue
						}
						pending, ok := pendingTools[blk.ToolUseID]
						if !ok {
							continue
						}
						delete(pendingTools, blk.ToolUseID)
						output := decodeToolResultContent(blk.Content)
						errMsg := ""
						if blk.IsError {
							errMsg = output
						}
						durationMS := now.Sub(pending.startedAt).Milliseconds()
						if durationMS < 0 {
							durationMS = 0
						}
						resultPayload := map[string]any{
							"tool":           pending.name,
							"output_bytes":   len([]byte(output)),
							"output_excerpt": outputSummaryFromRaw(output),
							"duration_ms":    durationMS,
							"error":          errMsg,
							"bead_id":        beadID,
							"elapsed_ms":     elapsedMS,
							"turn":           pending.turn,
						}
						if verbose {
							resultPayload["output"] = output
						}
						resultData, _ := json.Marshal(resultPayload)
						emit("tool.result", string(resultData))
					}
				}
			}
			lastRequestSentAt = now

		case "result":
			// Final event. Extract authoritative usage/cost/result text.
			if ev.Result != "" {
				res.FinalText = ev.Result
			}
			if ev.Usage.InputTokens > 0 {
				res.InputTokens = ev.Usage.InputTokens
			}
			if ev.Usage.OutputTokens > 0 {
				res.OutputTokens = ev.Usage.OutputTokens
			}
			if ev.TotalCostUSD > 0 {
				res.CostUSD = ev.TotalCostUSD
			}
			if ev.SessionID != "" {
				res.SessionID = ev.SessionID
			}
			if ev.IsError {
				res.IsError = true
			}
		}
	}
	if err := scanner.Err(); err != nil && !errors.Is(err, io.EOF) {
		return res, err
	}
	// Flush any tool calls whose tool_result never arrived (stream truncated
	// or the model made a tool call as its final action).
	if len(pendingTools) > 0 {
		flushAt := time.Now()
		for _, pending := range pendingTools {
			resultPayload := map[string]any{
				"tool":           pending.name,
				"output_bytes":   0,
				"output_excerpt": "",
				"duration_ms":    flushAt.Sub(pending.startedAt).Milliseconds(),
				"error":          "no tool_result received",
				"bead_id":        beadID,
				"elapsed_ms":     pending.elapsedMS,
				"turn":           pending.turn,
			}
			if verbose {
				resultPayload["output"] = ""
			}
			resultData, _ := json.Marshal(resultPayload)
			emit("tool.result", string(resultData))
		}
	}
	return res, nil
}

// decodeToolResultContent normalizes the polymorphic tool_result.content
// field (either a string or an array of {type:"text",text:"..."} blocks)
// into a single string suitable for the diagnostic tool.result output field.
func decodeToolResultContent(raw json.RawMessage) string {
	if len(raw) == 0 {
		return ""
	}
	var s string
	if err := json.Unmarshal(raw, &s); err == nil {
		return s
	}
	var blocks []struct {
		Type string `json:"type"`
		Text string `json:"text"`
	}
	if err := json.Unmarshal(raw, &blocks); err == nil {
		var sb strings.Builder
		for i, b := range blocks {
			if i > 0 {
				sb.WriteString("\n")
			}
			sb.WriteString(b.Text)
		}
		return sb.String()
	}
	return string(raw)
}

// resolveClaudeProgressLogDir picks the directory for the per-run claude
// progress JSONL trace. The per-run override (opts.SessionLogDir) takes
// precedence over the runner-wide Config.SessionLogDir so managed
// execute-bead invocations can redirect the trace into the DDx-owned
// execution bundle's embedded/ dir instead of the runner's default
// .ddx/agent-logs. Matches the agent_runner.go precedence pattern so the
// two harnesses behave identically under execute-bead.
func resolveClaudeProgressLogDir(opts RunArgs, cfg Config) string {
	if opts.SessionLogDir != "" {
		return opts.SessionLogDir
	}
	return cfg.SessionLogDir
}

// runClaudeStreaming is the streaming execution path for the claude harness.
// It launches the claude binary directly (bypassing the standard Executor
// abstraction so it can pipe stdout line-by-line), parses stream-json events
// as they arrive, and writes per-tool progress entries to a Fizeau-style
// JSONL file in opts.SessionLogDir (when set) or r.Config.SessionLogDir so
// `ddx server workers log` sees real-time activity.
//
// On success it returns a *Result shaped exactly like the non-streaming
// path, so callers downstream (processResult, session logging) are unchanged.
//
// If the claude CLI rejects the stream-json flags (older build, unsupported
// option), the caller falls back to the non-streaming path via
// runClaudeWithFallbackFn.
func runClaudeStreamingFn(r *Runner, ctx context.Context, harness harnessConfig, harnessName, model string, resolvedOpts RunArgs, prompt, execDir string, timeout time.Duration) (*Result, error) {
	args := BuildArgs(harness, buildArgsInputFromRunArgs(resolvedOpts), model)

	start := time.Now()
	runCtx, cancel := context.WithCancel(ctx)
	defer cancel()

	cmd := osexec.CommandContext(runCtx, harness.Binary, args...)
	if execDir != "" {
		cmd.Dir = execDir
	}
	if harness.PromptMode == "stdin" {
		cmd.Stdin = strings.NewReader(prompt)
	}

	stdoutPipe, err := cmd.StdoutPipe()
	if err != nil {
		return nil, err
	}
	stderrPipe, err := cmd.StderrPipe()
	if err != nil {
		return nil, err
	}

	if err := cmd.Start(); err != nil {
		return nil, err
	}

	// Open the progress log file. Using agent-<sessionID>.jsonl so
	// TailSessionLogs (which only reads files matching "agent-*.jsonl")
	// picks the stream up automatically.
	sessionID := fmt.Sprintf("claude-%d", time.Now().UnixNano())
	beadID := ""
	if resolvedOpts.Correlation != nil {
		beadID = resolvedOpts.Correlation["bead_id"]
	}
	var progressLog *os.File
	progressLogDir := resolveClaudeProgressLogDir(resolvedOpts, r.Config)
	if progressLogDir != "" {
		if err := os.MkdirAll(progressLogDir, 0o755); err == nil {
			logPath := filepath.Join(progressLogDir, "agent-"+sessionID+".jsonl")
			if f, err := os.OpenFile(logPath, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0o644); err == nil {
				progressLog = f
				defer progressLog.Close()
			}
		}
	}

	// Stream stdout: parse events as they arrive and mirror raw bytes into
	// a buffer so we can return the full output for session logging.
	var rawOut strings.Builder
	stdoutReader, stdoutWriter := io.Pipe()
	var parseResult *claudeStreamResult
	var parseErr error
	var parseWG sync.WaitGroup
	parseWG.Add(1)
	go func() {
		defer parseWG.Done()
		parseResult, parseErr = parseClaudeStream(stdoutReader, progressLog, sessionID, beadID, start)
	}()

	// Tee stdout into rawOut (for the final Result.Output) and the parser.
	stdoutDone := make(chan struct{})
	go func() {
		defer close(stdoutDone)
		// Pipe bytes through a tee so both the raw buffer and the parser see them.
		tee := io.TeeReader(stdoutPipe, &stringWriter{&rawOut})
		_, _ = io.Copy(stdoutWriter, tee)
		_ = stdoutWriter.Close()
	}()

	var stderrBuf strings.Builder
	stderrDone := make(chan struct{})
	go func() {
		defer close(stderrDone)
		_, _ = io.Copy(&stringWriter{&stderrBuf}, stderrPipe)
	}()

	// Idle-timeout watchdog: if no stdout progress for `timeout` duration,
	// cancel the context. The tee+parse goroutines handle activity naturally
	// via the pipe; for simplicity we use an overall deadline here. The
	// existing stream-json output is frequent enough that a long per-bead
	// deadline is the right behavior for operators.
	var timedOut bool
	if timeout > 0 {
		stop := make(chan struct{})
		go func() {
			select {
			case <-stop:
			case <-time.After(timeout):
				timedOut = true
				cancel()
			}
		}()
		defer close(stop)
	}

