			input: strings.Join([]string{
				`not json`,
				`{"type":"system","subtype":"init","session_id":"sess-xyz","model":"claude-sonnet-4-6"}`,
				`{garbage`,
				`{"type":"assistant","message":{"content":[{"type":"tool_use","id":"tu-2","name":"Read","input":{"path":"/tmp/x"}}],"usage":{"input_tokens":10,"output_tokens":5}}}`,
				`{"type":"result","subtype":"success","result":"ok","usage":{"input_tokens":10,"output_tokens":5},"total_cost_usd":0.001,"session_id":"sess-xyz"}`,
			}, "\n"),
			wantTurnCount:     1,
			wantToolCalls:     1,
			wantInputTokens:   10,
			wantOutputTokens:  5,
			wantCostUSD:       0.001,
			wantFinalText:     "ok",
			wantSessionID:     "sess-xyz",
			wantModel:         "claude-sonnet-4-6",
			wantProgressTypes: []string{"session.start", "llm.response", "tool.call", "tool.result"},
		},
		{
			name: "text-only assistant without tool_use still emits progress",
			input: strings.Join([]string{
				`{"type":"system","subtype":"init","session_id":"sess-t","model":"claude-sonnet-4-6"}`,
				`{"type":"assistant","message":{"content":[{"type":"text","text":"hello"}],"usage":{"input_tokens":3,"output_tokens":2}}}`,
				`{"type":"result","subtype":"success","result":"hello","usage":{"input_tokens":3,"output_tokens":2},"total_cost_usd":0.0001,"session_id":"sess-t"}`,
			}, "\n"),
			wantTurnCount:     1,
			wantToolCalls:     0,
			wantInputTokens:   3,
			wantOutputTokens:  2,
			wantCostUSD:       0.0001,
			wantFinalText:     "hello",
			wantSessionID:     "sess-t",
			wantModel:         "claude-sonnet-4-6",
			wantProgressTypes: []string{"session.start", "llm.response"},
		},
	}

	for _, tc := range cases {
		tc := tc
		t.Run(tc.name, func(t *testing.T) {
			var progressBuf bytes.Buffer
			start := time.Now().Add(-3 * time.Second) // exercise elapsed_ms > 0
			res, err := parseClaudeStream(strings.NewReader(tc.input), &progressBuf, "sess-test", "ddx-12345678", start)
			require.NoError(t, err)
			require.NotNil(t, res)

			assert.Equal(t, tc.wantTurnCount, res.TurnCount, "turn count")
			assert.Equal(t, tc.wantToolCalls, res.ToolCalls, "tool call count")
			assert.Equal(t, tc.wantInputTokens, res.InputTokens, "input tokens")
			assert.Equal(t, tc.wantOutputTokens, res.OutputTokens, "output tokens")
			assert.InDelta(t, tc.wantCostUSD, res.CostUSD, 1e-9, "cost usd")
			assert.Equal(t, tc.wantFinalText, res.FinalText, "final text")
			assert.Equal(t, tc.wantSessionID, res.SessionID, "session id")
			assert.Equal(t, tc.wantModel, res.Model, "model")
			assert.False(t, res.IsError)

			// Walk the emitted progress lines and confirm the expected types
			// appear in order.
			var gotTypes []string
			for _, line := range strings.Split(strings.TrimSpace(progressBuf.String()), "\n") {
				if line == "" {
					continue
				}
				var entry map[string]any
				require.NoError(t, json.Unmarshal([]byte(line), &entry), "progress line must be valid JSON: %s", line)
				t, _ := entry["type"].(string)
				gotTypes = append(gotTypes, t)
			}
			assert.Equal(t, tc.wantProgressTypes, gotTypes, "progress event types (in order)")

			// Spot-check that at least one tool.call line carries the bead_id
			// so execute-bead operators can grep the log stream.
			if tc.wantToolCalls > 0 {
				assert.Contains(t, progressBuf.String(), `"bead_id":"ddx-12345678"`)
				assert.Contains(t, progressBuf.String(), `"tool.call"`)
			}
		})
	}
}

// TestParseClaudeStreamDiagnosticMode asserts that with DDX_LOG_VERBOSE=1
// the parser adds raw body fields without changing event ordering or types.
func TestParseClaudeStreamDiagnosticMode(t *testing.T) {
	t.Setenv("DDX_LOG_VERBOSE", "1")
	input := strings.Join([]string{
		`{"type":"system","subtype":"init","session_id":"sess-v","model":"claude-sonnet-4-6"}`,
		`{"type":"assistant","message":{"id":"m-1","model":"claude-sonnet-4-6","stop_reason":"tool_use","content":[{"type":"text","text":"running ls"},{"type":"tool_use","id":"tu-1","name":"Bash","input":{"command":"ls"}}],"usage":{"input_tokens":120,"output_tokens":42,"cache_creation_input_tokens":10,"cache_read_input_tokens":80}}}`,
		`{"type":"user","message":{"content":[{"type":"tool_result","tool_use_id":"tu-1","content":"README.md\nfoo.go","is_error":false}]}}`,
		`{"type":"assistant","message":{"id":"m-2","model":"claude-sonnet-4-6","stop_reason":"end_turn","content":[{"type":"text","text":"All done."}],"usage":{"input_tokens":260,"output_tokens":88,"cache_creation_input_tokens":0,"cache_read_input_tokens":200}}}`,
		`{"type":"result","subtype":"success","is_error":false,"duration_ms":1200,"result":"All done.","usage":{"input_tokens":260,"output_tokens":88},"total_cost_usd":0.0123,"session_id":"sess-v"}`,
	}, "\n")

	var progressBuf bytes.Buffer
	res, err := parseClaudeStream(strings.NewReader(input), &progressBuf, "sess-v", "ddx-verbose", time.Now())
	require.NoError(t, err)
	require.NotNil(t, res)

	type envelope struct {
		Type string                 `json:"type"`
		Data map[string]interface{} `json:"data"`
	}
	var llmResponses []map[string]interface{}
	var toolCalls []map[string]interface{}
	for _, line := range strings.Split(strings.TrimSpace(progressBuf.String()), "\n") {
		if line == "" {
			continue
		}
		var env envelope
		require.NoError(t, json.Unmarshal([]byte(line), &env))
		switch env.Type {
		case "llm.response":
			llmResponses = append(llmResponses, env.Data)
		case "tool.call":
			toolCalls = append(toolCalls, env.Data)
		}
	}
	require.Len(t, llmResponses, 2, "expected two llm.response events")
	var toolResults []map[string]interface{}
	for _, line := range strings.Split(strings.TrimSpace(progressBuf.String()), "\n") {
		if line == "" {
			continue
		}
		var env envelope
		require.NoError(t, json.Unmarshal([]byte(line), &env))
		if env.Type == "tool.result" {
			toolResults = append(toolResults, env.Data)
		}
	}
	require.Len(t, toolCalls, 1, "expected one tool.call event")
	require.Len(t, toolResults, 1, "expected one tool.result event")

	// llm.response[0] — assistant turn that issued a tool_use.
	first := llmResponses[0]
	assert.Equal(t, "running ls", first["content"], "diagnostic llm.response must include content")
	assert.Equal(t, "tool_use", first["finish_reason"], "diagnostic llm.response must include finish_reason")
	usage, ok := first["usage"].(map[string]interface{})
	require.True(t, ok, "diagnostic llm.response must include usage object")
	assert.EqualValues(t, 120, usage["input_tokens"])
	assert.EqualValues(t, 42, usage["output_tokens"])
	assert.EqualValues(t, 10, usage["cache_creation_input_tokens"])
	assert.EqualValues(t, 80, usage["cache_read_input_tokens"])
	assert.EqualValues(t, 162, usage["total_tokens"])
	assert.EqualValues(t, len("running ls"), first["response_bytes"])
	assert.EqualValues(t, len(`{"command":"ls"}`), first["tool_input_bytes"])

	// llm.response[1] — final text turn.
	second := llmResponses[1]
	assert.Equal(t, "All done.", second["content"])
	assert.Equal(t, "end_turn", second["finish_reason"])

	// tool.call stays an immediate request event; tool.result carries output.
	tc := toolCalls[0]
	assert.Equal(t, "Bash", tc["tool"])
	input2, ok := tc["input"].(map[string]interface{})
	require.True(t, ok, "tool.call must include decoded input")

	require.True(t, ok, "tool.call must include decoded input")
	assert.Equal(t, "ls", input2["command"])
	assert.EqualValues(t, len(`{"command":"ls"}`), tc["input_bytes"])
	assert.Equal(t, "ddx-verbose", tc["bead_id"])
	assert.EqualValues(t, 1, tc["turn"])

	result := toolResults[0]
	assert.Equal(t, "Bash", result["tool"])
	assert.Equal(t, "README.md\nfoo.go", result["output"], "diagnostic tool.result must include output")
	assert.Equal(t, "2 lines", result["output_excerpt"], "tool.result should include a compact output hint")
	assert.Equal(t, "", result["error"], "tool.result must include error field (empty on success)")
	assert.EqualValues(t, len("README.md\nfoo.go"), toolResults[0]["output_bytes"])
}

// TestParseClaudeStreamStandardDefault asserts that the standard schema is
// the default: raw diagnostic bodies are omitted, but compact payload sizes
// and stable tool.call/tool.result events are still emitted.
func TestParseClaudeStreamStandardDefault(t *testing.T) {
	t.Setenv("DDX_LOG_VERBOSE", "")
	input := strings.Join([]string{
		`{"type":"system","subtype":"init","session_id":"sess-l","model":"claude-sonnet-4-6"}`,
		`{"type":"assistant","message":{"id":"m-1","stop_reason":"tool_use","content":[{"type":"tool_use","id":"tu-1","name":"Bash","input":{"command":"ls"}}],"usage":{"input_tokens":1,"output_tokens":1}}}`,
		`{"type":"user","message":{"content":[{"type":"tool_result","tool_use_id":"tu-1","content":"ok"}]}}`,
		`{"type":"result","subtype":"success","result":"ok","usage":{"input_tokens":1,"output_tokens":1},"total_cost_usd":0.0001,"session_id":"sess-l"}`,
	}, "\n")

	var progressBuf bytes.Buffer
	_, err := parseClaudeStream(strings.NewReader(input), &progressBuf, "sess-l", "ddx-standard", time.Now())
	require.NoError(t, err)

	hasField := func(eventType, field string) bool {
		for _, line := range strings.Split(strings.TrimSpace(progressBuf.String()), "\n") {
			if line == "" {
				continue
			}
			var env struct {
				Type string                 `json:"type"`
				Data map[string]interface{} `json:"data"`
			}
			if json.Unmarshal([]byte(line), &env) != nil || env.Type != eventType {
				continue
			}
			if _, ok := env.Data[field]; ok {
				return true
			}
		}
		return false
	}
	assert.False(t, hasField("llm.response", "content"), "standard llm.response must not include content")
	assert.False(t, hasField("llm.response", "finish_reason"), "standard llm.response must not include finish_reason")
	assert.False(t, hasField("llm.response", "usage"), "standard llm.response must not include verbose usage object")
	assert.False(t, hasField("tool.result", "output"), "standard tool.result must not include output")
	assert.True(t, hasField("tool.call", "input_bytes"), "standard tool.call must include input_bytes")
	assert.True(t, hasField("tool.result", "output_bytes"), "standard tool.result must include output_bytes")
	assert.True(t, hasField("tool.result", "output_excerpt"), "standard tool.result must include compact output context")
}

