// FormatServiceProgressEntries formats canonical Fizeau progress payloads
// directly. It is used by callers that already have structured ServiceEvent
// data and should not round-trip through session-log JSONL line parsing.
func FormatServiceProgressEntries(entries []agentlib.ServiceProgressData) string {
	var sb strings.Builder
	for _, entry := range entries {
		raw, err := json.Marshal(entry)
		if err != nil {
			continue
		}
		var data map[string]any
		if err := json.Unmarshal(raw, &data); err != nil {
			continue
		}
		if line := formatProgressLogEntry(map[string]any{
			"type": "progress",
			"data": data,
		}); line != "" {
			sb.WriteString(line)
		}
	}
	return sb.String()
}

func truncateStr(s string, maxLen int) string {
	if len(s) <= maxLen {
		return s
	}
	return s[:maxLen-1] + "…"
}

type payloadHint struct {
	label string
	bytes int
}

func formatPayloadHints(hints []payloadHint) string {
	parts := make([]string, 0, len(hints))
	for _, hint := range hints {
		if hint.bytes <= 0 {
			continue
		}
		parts = append(parts, hint.label+"="+formatByteSize(hint.bytes))
	}
	return strings.Join(parts, " ")
}

func formatSizeSuffix(label string, bytes int) string {
	if bytes <= 0 {
		return ""
	}
	return ", " + label + "=" + formatByteSize(bytes)
}

func formatByteSize(bytes int) string {
	switch {
	case bytes <= 0:
		return "0B"
	case bytes < 1024:
		return fmt.Sprintf("%dB", bytes)
	case bytes < 1024*1024:
		return fmt.Sprintf("%.1fKB", float64(bytes)/1024)
	default:
		return fmt.Sprintf("%.1fMB", float64(bytes)/(1024*1024))
	}
}

func encodedPayloadSize(v any) int {
	if v == nil {
		return 0
	}
	switch x := v.(type) {
	case string:
		return len([]byte(x))
	case json.RawMessage:
		return len(x)
	case []byte:
		return len(x)
	default:
		raw, err := json.Marshal(v)
		if err != nil {
			return 0
		}
		return len(raw)
	}
}

func formatProgressLogEntry(entry map[string]any) string {
	data, _ := entry["data"].(map[string]any)
	phase, _ := data["phase"].(string)
	state, _ := data["state"].(string)
	if line := formatStructuredProgressLine(phase, state, data); line != "" {
		return "  " + line + "\n"
	}
	message, _ := data["message"].(string)
	if message != "" {
		return fmt.Sprintf("  %s\n", truncateStr(message, 120))
	}
	return ""
}

func formatStructuredProgressLine(phase, state string, data map[string]any) string {
	switch phase {

	switch phase {
	case "thinking":
		return formatThinkingProgressLine(state, data)
	case "tool":
		return formatToolProgressLine(state, data)
	case "response":
		return formatResponseProgressLine(state, data)
	case "context":
		return formatContextProgressLine(state, data)
	case "compaction":
		return formatCompactionProgressLine(state, data)
	default:
		return ""
	}
}

func formatThinkingProgressLine(state string, data map[string]any) string {
	switch state {
	case "start":
		return "thinking ..."
	case "update":
		msg := progressSummaryFromData(data)
		if msg == "" {
			msg = "thinking update ..."
		} else {
			msg = "thinking update: " + msg
		}
		return truncateStr(msg, 120)
	case "complete":
		tokens := progressTokenCount(data, "output_tokens", "total_tokens", "input_tokens")
		duration := progressDurationString(data)
		if tokens > 0 && duration != "" {
			return fmt.Sprintf("thinking complete %d tok in %s%s", tokens, duration, progressThroughputSuffix(data, tokens))
		}
		if tokens > 0 {
			return fmt.Sprintf("thinking complete %d tok", tokens)
		}
		if duration != "" {
			return fmt.Sprintf("thinking complete in %s", duration)
		}
		return "thinking complete"
	default:
		return ""
	}
}

func formatToolProgressLine(state string, data map[string]any) string {
	toolName, _ := data["tool_name"].(string)
	command, _ := data["command"].(string)
	display := compactProgressToolDisplay(data, toolName, command, 96)
	switch state {
	case "start":
		if display != "" {
			return truncateStr("> "+display, 120)
		}
		return "> tool"
	case "complete":
		tokens := progressTokenCount(data, "total_tokens", "output_tokens", "input_tokens")
		duration := progressDurationString(data)
		outputSummary := progressOutputSummary(data)
		if outputSummary != "" {
			display = compactProgressToolDisplay(data, toolName, command, 80)
		}
		line := "ok"
		if display != "" {
			line += " " + display
		}
		if outputSummary != "" {
			line += " < " + outputSummary
		}
		suffix := ""
		if duration != "" {
			suffix = " " + duration
		}
		if tokens > 0 {
			suffix += fmt.Sprintf(" %dtok", tokens)
		}
		if throughput := progressThroughputText(data, tokens); throughput != "" {
			if suffix != "" {
				suffix += ", " + throughput
			} else {
				suffix = " " + throughput
			}
		}
		return truncateStr(line, maxInt(1, 120-len(suffix))) + suffix
	default:
		return ""
	}
}

func formatTokenThroughput(tokens int, durationMS int) string {
	if tokens <= 0 || durationMS <= 0 {
		return ""
	}
	return fmt.Sprintf("%s tok/s", strconv.FormatFloat(float64(tokens)*1000/float64(durationMS), 'f', 1, 64))
}

func progressThroughputSuffix(data map[string]any, tokens int) string {
	throughput := progressThroughputText(data, tokens)
	if throughput == "" {
		return ""
	}
	return ", " + throughput
}

func progressThroughputText(data map[string]any, tokens int) string {
	if throughput := progressFloat(data, "tok_per_sec"); throughput > 0 {
		return fmt.Sprintf("%s tok/s", strconv.FormatFloat(throughput, 'f', 1, 64))
	}
	return formatTokenThroughput(tokens, progressInt(data, "duration_ms"))
}

func progressOutputSummary(data map[string]any) string {
	if data == nil {
		return ""
	}
	if summary, _ := data["output_summary"].(string); strings.TrimSpace(summary) != "" {
		return compactOutputSummaryLimit(summary, 56)
	}
	parts := make([]string, 0, 3)
	if bytes := progressInt(data, "output_bytes"); bytes > 0 {
		parts = append(parts, "out="+formatByteSize(bytes))
	}
	if lines := progressInt(data, "output_lines"); lines > 0 {
		parts = append(parts, fmt.Sprintf("%d lines", lines))
	}
	if excerpt, _ := data["output_excerpt"].(string); strings.TrimSpace(excerpt) != "" {
		parts = append(parts, compactOutputSummaryLimit(excerpt, 56))
	}
	if len(parts) == 0 {
		return ""
	}
	return compactOutputSummary(strings.Join(parts, " "))
}

func compactProgressToolDisplay(data map[string]any, toolName, command string, limit int) string {
	action := progressActionFromData(data)
	if action == "" {
		action = describeToolCommand(toolName, command)
	}
	if action == "" {
		action = compactToolDisplayLimit(toolName, command, limit)
	}
	prefix := compactProgressEventIdentity(data)
	if prefix != "" {
		action = prefix + " " + action
	}
	return truncateStr(action, limit)
}

func progressActionFromData(data map[string]any) string {
	if data == nil {
		return ""
	}
	for _, key := range []string{"description", "action"} {
		if value, ok := data[key].(string); ok && strings.TrimSpace(value) != "" {
			return compactTargetedAction(value, data)
		}
	}
	return ""
}

func compactTargetedAction(action string, data map[string]any) string {
	action = strings.Join(strings.Fields(strings.TrimSpace(action)), " ")
	target := progressTargetFromData(data)
	compactedTarget := compactPathToken(target, 36)
	if target == "" || strings.Contains(action, target) || strings.Contains(action, compactedTarget) {
		return action
	}
	return action + " to " + compactedTarget
}

func progressTargetFromData(data map[string]any) string {
	for _, key := range []string{"target", "path", "file"} {
		if value, ok := data[key].(string); ok && strings.TrimSpace(value) != "" {
			return strings.TrimSpace(value)
		}
	}
	return ""
}

func compactProgressEventIdentity(data map[string]any) string {
	if data == nil {
		return ""
	}
	taskID, _ := data["task_id"].(string)
	taskID = strings.TrimSpace(taskID)
	turn := progressTurnNumber(data)
	switch {
	case taskID != "" && turn > 0:
		return fmt.Sprintf("%s %d", taskID, turn)
	case taskID != "":
		return taskID
	case turn > 0:
		return fmt.Sprintf("%d", turn)
	default:
		return ""
	}
}

func progressTurnNumber(data map[string]any) int {

func progressTurnNumber(data map[string]any) int {
	if turn := progressInt(data, "turn_index"); turn > 0 {
		return turn
	}
	return progressInt(data, "round")
}

func describeToolCommand(toolName, command string) string {
	command = strings.TrimSpace(command)
	if command == "" {
		return strings.TrimSpace(toolName)
	}
	command = unwrapToolCommandSummary(command)
	command = stripShellLoginWrapper(command)
	command = firstShellCommandSegment(command)
	command = strings.Join(strings.Fields(command), " ")
	fields := strings.Fields(command)
	if len(fields) == 0 {
		return ""
	}
	switch fields[0] {
	case "sed":
		if len(fields) >= 4 && fields[1] == "-n" {
			return "inspect " + strings.Trim(fields[2], "'\"") + " in " + compactPathToken(fields[3], 36)
		}
	case "cat":
		if len(fields) >= 2 {
			return "inspect " + compactPathToken(fields[len(fields)-1], 36)
		}
	case "rg":
		return describeRipgrepCommand(fields)
	case "go":
		if len(fields) >= 2 && fields[1] == "test" {
			return "test " + strings.Join(compactPathTokens(fields[2:], 64), " ")
		}
	case "git":
		return describeGitCommand(fields)
	}
	return compactToolDisplayLimit(toolName, command, 96)
}

func describeRipgrepCommand(fields []string) string {
	target := ""
	pattern := ""
	for _, field := range fields[1:] {
		if strings.HasPrefix(field, "-") {
			continue
		}
		if pattern == "" {
			pattern = strings.Trim(field, "'\"")
			continue
		}
		target = field
	}
	if target != "" && pattern != "" {
		return "search " + strconv.Quote(truncateStr(pattern, 32)) + " in " + compactPathToken(target, 36)
	}
	if pattern != "" {
		return "search " + strconv.Quote(truncateStr(pattern, 32))
	}
	return "search"
}

func describeGitCommand(fields []string) string {
	if len(fields) < 2 {
		return "git"
	}
	switch fields[1] {
	case "add":
		if len(fields) > 2 {
			return "stage " + strings.Join(compactPathTokens(fields[2:], 36), " ")
		}
		return "stage changes"
	case "commit":
		return "commit changes"
	case "diff":
		return "inspect diff"
	case "status":
		return "inspect git status"
	case "log":
		return "inspect git log"
	default:
		return "git " + fields[1]
	}
}

func compactPathTokens(tokens []string, limit int) []string {
	out := make([]string, 0, len(tokens))
	for _, token := range tokens {
		out = append(out, compactPathToken(token, limit))
	}
	return out
}

func compactOutputExcerpt(data map[string]any) string {
	if data == nil {
		return ""
	}
	for _, key := range []string{"output_excerpt", "output_summary"} {
		if value, ok := data[key].(string); ok && strings.TrimSpace(value) != "" {
			return compactOutputSummary(value)
		}
	}
	if output, ok := data["output"].(string); ok {
		return outputSummaryFromRaw(output)
	}
	return ""
}

func compactOutputSummary(summary string) string {
	return compactOutputSummaryLimit(summary, 80)
}

func compactOutputSummaryLimit(summary string, limit int) string {
	summary = strings.Join(strings.Fields(strings.TrimSpace(summary)), " ")
	return truncateStr(summary, limit)
}

func outputSummaryFromRaw(output string) string {
	output = strings.TrimSpace(output)
	if output == "" {
		return ""
	}
	byteCount := len([]byte(output))
	lineCount := strings.Count(output, "\n") + 1
	parts := []string{}
	if lineCount == 1 {
		parts = append(parts, "1 line")
	} else {
		parts = append(parts, fmt.Sprintf("%d lines", lineCount))
	}
	if byteCount > 40 {
		for _, line := range strings.Split(output, "\n") {
			line = strings.TrimSpace(line)
			if line != "" {
				parts = append(parts, strconv.Quote(truncateStr(line, 48)))
				break
			}
		}
	}
	return compactOutputSummary(strings.Join(parts, " "))
}

func compactToolDisplay(toolName, command string) string {
	return compactToolDisplayLimit(toolName, command, 96)
}

func compactToolDisplayLimit(toolName, command string, limit int) string {
	display := strings.TrimSpace(command)
	if display == "" {
		display = strings.TrimSpace(toolName)
	}
	display = unwrapToolCommandSummary(display)
	display = stripShellLoginWrapper(display)
	display = firstShellCommandSegment(display)
	fields := strings.Fields(display)
	for i := range fields {
		fields[i] = compactPathToken(fields[i], 36)
	}
	display = strings.Join(fields, " ")
	return truncateStr(display, limit)

	//    the claim is not leaked even if the kill blocks for the full grace.
	if beadID != "" {
		store := bead.NewStore(filepath.Join(projectRoot, ".ddx"))
		body := fmt.Sprintf(
			"worker=%s runtime=%s stalled=%s pid=%d reason=%s",
			id, runtime.Round(time.Second), stalled.Round(time.Second), pid, reason,
		)
		_ = store.AppendEvent(beadID, bead.BeadEvent{
			Kind:      "bead.reaped",
			Summary:   reason,
			Body:      body,
			Actor:     "ddx-watchdog",
			Source:    "server-workers",
			CreatedAt: now,
		})
		_ = store.Unclaim(beadID)
	}

	// 2. Escalate to the worker process group if we know the PID.
	_, _, _, grace := m.watchdogDeadlines()
	if pid > 0 {
		terminateProcessGroup(pid, grace)
	}

	// 3. Cancel the goroutine so any in-process code sees context.Canceled.
	if handle.cancel != nil {
		handle.cancel()
	}

	// 4. Flip state=reaped and persist. runWorker may still race to
	//    overwrite this with "exited" when it returns; that's fine — the
	//    bead.reaped event plus released claim are the durable record.
	m.mu.Lock()
	handle.record.State = "reaped"
	handle.record.Status = "reaped"
	handle.record.ReapReason = reason
	if handle.record.FinishedAt.IsZero() {
		handle.record.FinishedAt = now
	}
	if handle.record.LastError == "" {
		handle.record.LastError = fmt.Sprintf("watchdog reaped worker after runtime=%s stalled=%s",
			runtime.Round(time.Second), stalled.Round(time.Second))
	}
	dir := filepath.Join(m.rootDir, id)
	snapshot := handle.record
	m.mu.Unlock()

	_ = m.writeRecord(dir, snapshot)
}

func (m *WorkerManager) Logs(id string) (string, string, error) {
	m.mu.Lock()
	if handle, ok := m.workers[id]; ok {
		log := handle.logBuf.String()
		sessionLog := m.readActiveSessionLog(handle)
		m.mu.Unlock()
		if sessionLog != "" {
			return log + "\n" + sessionLog, "", nil
		}
		return log, "", nil
	}
	m.mu.Unlock()

	// Fall back to reading from disk for completed workers
	rec, err := m.Show(id)
	if err != nil {
		return "", "", err
	}
	if rec.StdoutPath == "" {
		return "", "", nil
	}
	data, err := os.ReadFile(filepath.Join(m.projectRoot, rec.StdoutPath))
	if err != nil {
		return "", "", err
	}
	return string(data), "", nil
}

// drainProgress reads ProgressEvents from ch and:
//  1. Updates the WorkerRecord's CurrentAttempt, RecentPhases, and LastAttempt fields.
//  2. Broadcasts each event to all active SSE subscribers for the worker.
//
// It runs as a goroutine alongside runWorker; it exits when ch is closed.
func (m *WorkerManager) drainProgress(workerID string, handle *workerHandle, ch <-chan agent.ProgressEvent) {
	const maxRecentPhases = 20
	for evt := range ch {
		m.mu.Lock()
		rec := handle.record

		// Substate signals (ddx-dc157075 AC #5). loop.idle marks the worker as
		// "idle" without disturbing CurrentAttempt; loop.active clears it when
		// the loop picks up the next candidate. These are not real attempt
		// phases, so they bypass the normal RecentPhases / CurrentAttempt path.
		switch evt.Phase {
		case "loop.idle":
			rec.Substate = "idle"
			handle.record = rec
			m.mu.Unlock()
			continue
		case "loop.active":
			rec.Substate = ""
			handle.record = rec
			m.mu.Unlock()
			continue
		}

		if !evt.Heartbeat {
			// Phase-transition: record in RecentPhases (capped at maxRecentPhases)
			rec.RecentPhases = append(rec.RecentPhases, PhaseTransition{
				Phase:    evt.Phase,
				TS:       evt.TS,
				PhaseSeq: evt.PhaseSeq,
			})
			if len(rec.RecentPhases) > maxRecentPhases {
				rec.RecentPhases = rec.RecentPhases[len(rec.RecentPhases)-maxRecentPhases:]
			}
			// Stamp lastPhaseTS so the watchdog can detect stalled attempts.
			handle.lastPhaseTS = evt.TS
		}

		if terminalPhases[evt.Phase] {
			// Increment live counters so Show() reflects progress before the
			// loop exits. runWorker will overwrite these with authoritative
			// loopResult values after progressDone is signalled, which is the
			// same value — so no double-counting occurs.
			rec.Attempts++
			if evt.Phase == "done" {
				rec.Successes++
			} else {
				rec.Failures++
			}

			// Move CurrentAttempt → LastAttempt
			if rec.CurrentAttempt != nil {
				rec.LastAttempt = &LastAttemptInfo{
					AttemptID: rec.CurrentAttempt.AttemptID,
					BeadID:    rec.CurrentAttempt.BeadID,
					Phase:     evt.Phase,
					StartedAt: rec.CurrentAttempt.StartedAt,
					EndedAt:   evt.TS,
					ElapsedMS: evt.ElapsedMS,
				}
			}
			rec.CurrentAttempt = nil
		} else {
			// Update or initialise CurrentAttempt
			if rec.CurrentAttempt == nil {
				rec.CurrentAttempt = &CurrentAttemptInfo{
					AttemptID: evt.AttemptID,
					BeadID:    evt.BeadID,
					StartedAt: evt.TS,
				}
			}
			rec.CurrentAttempt.AttemptID = evt.AttemptID
			rec.CurrentAttempt.BeadID = evt.BeadID
			rec.CurrentAttempt.Phase = evt.Phase

			rec.CurrentAttempt.Phase = evt.Phase
			rec.CurrentAttempt.PhaseSeq = evt.PhaseSeq
			rec.CurrentAttempt.ElapsedMS = evt.ElapsedMS
			if evt.Harness != "" {
				rec.CurrentAttempt.Harness = evt.Harness
			}
			if evt.Model != "" {
				rec.CurrentAttempt.Model = evt.Model
			}
			if evt.Profile != "" {
				rec.CurrentAttempt.Profile = evt.Profile
			}
		}

		handle.record = rec

		// Broadcast to SSE subscribers (non-blocking; slow subscribers are dropped)
		subs := handle.progressSubs
		m.mu.Unlock()

		for _, sub := range subs {
			select {
			case sub <- evt:
			default:
				// Subscriber channel full — skip rather than block
			}
		}
	}

	// Channel closed: clear CurrentAttempt if still set (worker exited)
	m.mu.Lock()
	if handle.record.CurrentAttempt != nil {
		handle.record.CurrentAttempt = nil
	}
	// Close and remove all subscriber channels
	for _, sub := range handle.progressSubs {
		close(sub)
	}
	handle.progressSubs = nil
	m.mu.Unlock()

	// Signal that no further events will arrive
	if handle.progressDone != nil {
		close(handle.progressDone)
	}
}

// SubscribeProgress returns a channel that receives ProgressEvents for the
// given worker, plus an unsubscribe function. If the worker is not active or
// has already finished, the returned channel is pre-closed so SSE handlers
// can detect idle/done state immediately.
func (m *WorkerManager) SubscribeProgress(workerID string) (<-chan agent.ProgressEvent, func()) {
	m.mu.Lock()
	defer m.mu.Unlock()

	handle, ok := m.workers[workerID]
	if !ok {
		// Worker never started or was never registered
		ch := make(chan agent.ProgressEvent)
		close(ch)
		return ch, func() {}
	}

	// Check if drainProgress has already exited (worker done)
	if handle.progressDone != nil {
		select {
		case <-handle.progressDone:
			ch := make(chan agent.ProgressEvent)
			close(ch)
			return ch, func() {}
		default:
		}
	}

	ch := make(chan agent.ProgressEvent, 64)
	handle.progressSubs = append(handle.progressSubs, ch)

	unsub := func() {
		m.mu.Lock()
		defer m.mu.Unlock()
		if h, ok := m.workers[workerID]; ok {
			for i, sub := range h.progressSubs {
				if sub == ch {
					h.progressSubs = append(h.progressSubs[:i], h.progressSubs[i+1:]...)
					break
				}
			}
		}
	}
	return ch, unsub
}

func (m *WorkerManager) runWorker(ctx context.Context, id, dir string, spec ExecuteLoopWorkerSpec, projectRoot string, handle *workerHandle, log io.Writer, eventSink io.WriteCloser, progressCh chan agent.ProgressEvent) {
	if eventSink != nil {
		defer eventSink.Close() //nolint:errcheck
	}
	store := bead.NewStore(filepath.Join(projectRoot, ".ddx"))
	rcfg, _ := config.LoadAndResolve(projectRoot, config.CLIOverrides{
		Assignee:          "ddx",
		Harness:           spec.Harness,
		Model:             spec.Model,
		Provider:          spec.Provider,
		ModelRef:          spec.ModelRef,
		Profile:           agent.NormalizeRoutingProfile(spec.Profile),
		Effort:            spec.Effort,
		OpaquePassthrough: spec.OpaquePassthrough,
	})

	var worker *agent.ExecuteBeadWorker
	var costCap *policyescalation.CostCapTracker
	if m.BeadWorkerFactory != nil {
		worker = m.BeadWorkerFactory(store)
	} else {
		// Build an executor that calls agent.ExecuteBead in-process, then
		// submits the result to the project's land coordinator. The
		// coordinator (a single goroutine per projectRoot) serializes all
		// target-ref writes for this project — this is the server-side
		// implementation of the human-PR landing model. See ddx-8746d8a6
		// for the rationale. Prior to this rewrite, runWorker never called
		// LandBeadResult at all, so commits produced by server-managed
		// workers were silently lost (ddx-e14efc58).
		coordinator := m.LandCoordinators.Get(projectRoot)

		// singleTierAttempt runs one execution at a specific harness/model.
		// The caller controls MinPower per rung; this helper keeps the
		// profile stable and only advances the power floor.
		singleTierAttempt := func(ctx context.Context, beadID string, requestedMinPower int, resolvedHarness, resolvedProvider, resolvedModel string) (agent.ExecuteBeadReport, error) {
			gitOps := &agent.RealGitOps{}
			attemptProvider := spec.Provider
			if resolvedProvider != "" {
				attemptProvider = resolvedProvider
			}
			attemptRcfg, _ := config.LoadAndResolve(projectRoot, config.CLIOverrides{
				Harness:           resolvedHarness,
				Model:             resolvedModel,
				Provider:          attemptProvider,
				ModelRef:          spec.ModelRef,
				Profile:           rcfg.Profile(),
				Effort:            spec.Effort,
				MinPower:          requestedMinPower,
				OpaquePassthrough: spec.OpaquePassthrough,
			})
			beadStore := bead.NewStore(filepath.Join(projectRoot, ".ddx"))
			res, err := agent.ExecuteBeadWithConfig(ctx, projectRoot, beadID, attemptRcfg, agent.ExecuteBeadRuntime{
				BeadEvents: beadStore,
				BeadCancel: beadStore,
			}, gitOps)
			if err != nil && res == nil {
				return agent.ExecuteBeadReport{}, err
			}
			// Preserve operator-cancel results as-is; the worker has already
			// classified them (preserved / operator_cancel / preserved_needs_review)
			// and overriding here would lose the cancel signal.
			operatorCancel := res != nil && res.Reason == agent.OperatorCancelReason
			if res != nil && res.ResultRev != "" && res.ResultRev != res.BaseRev && res.ExitCode == 0 && !operatorCancel {
				if landErr := evaluateGatesAndSubmit(projectRoot, res, gitOps, coordinator, landSafetyConfigFromConfig(projectRoot), log); landErr != nil && err == nil {
					err = landErr
				}
			} else if res != nil && res.ResultRev == res.BaseRev && !operatorCancel {
				res.Outcome = "no-changes"
				res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
			} else if res != nil && res.ExitCode != 0 && !operatorCancel {
				res.Outcome = "preserved"
				res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
			}
			// Safety net: commit any leftover evidence files that Land()
			// did not pick up (e.g. HEAD was detached, or no land ran).
			if res != nil && res.AttemptID != "" {
				_ = agent.VerifyCleanWorktree(projectRoot, res.AttemptID)
			}
			if err != nil {
				return agent.ExecuteBeadReport{}, err
			}
			return agent.ExecuteBeadReport{
				BeadID:             res.BeadID,
				AttemptID:          res.AttemptID,
				WorkerID:           res.WorkerID,
				Harness:            res.Harness,
				Provider:           res.Provider,
				Model:              res.Model,
				ActualPower:        res.ActualPower,
				Status:             res.Status,
				Detail:             res.Detail,
				SessionID:          res.SessionID,
				BaseRev:            res.BaseRev,
				ResultRev:          res.ResultRev,
				PreserveRef:        res.PreserveRef,
